// ===== 精简版学习反馈消息 =====
// 不使用红色错误提示，不判定对错
// 仅提供鼓励性文字和可视化反馈引导

import { playShake, playSuccess, playCelebrate } from "@/lib/sounds";

/** 鼓励继续探索的消息 */
export const ENCOURAGE_MESSAGES = [
  "再想想看，你可以的！",
  "换个角度试试？",
  "没关系，多试几次就明白了！",
  "你已经很接近了！",
] as const;

/** 完成步骤的肯定消息 */
export const COMPLETE_MESSAGES = [
  "太棒了！你完成了这一步！",
  "做得真好！继续往下探索吧！",
  "恭喜！你又学会了一个新本领！",
] as const;

/** 随机获取鼓励消息 */
export function getRandomEncourage(): string {
  return ENCOURAGE_MESSAGES[Math.floor(Math.random() * ENCOURAGE_MESSAGES.length)];
}

/** 随机获取完成消息 */
export function getRandomComplete(): string {
  return COMPLETE_MESSAGES[Math.floor(Math.random() * COMPLETE_MESSAGES.length)];
}

/**
 * 触发抖动反馈（替代红色错误提示）
 * 在调用方给元素添加 animate-shake class，延时后移除
 * 自动播放 shake 音效
 */
export function triggerShake(element: HTMLElement | null): void {
  if (!element) return;
  playShake();
  element.classList.remove("animate-shake");
  // 强制 reflow 以重新触发动画
  void element.offsetWidth;
  element.classList.add("animate-shake");
  setTimeout(() => {
    element.classList.remove("animate-shake");
  }, 600);
}

/** 安全的 shake 触发：通过 ID 获取元素，null 安全 */
export function safeShake(id: string): void {
  const el = document.getElementById(id);
  if (el) triggerShake(el);
}

/** 成功反馈 — 带音效 */
export function feedbackSuccess() {
  playSuccess();
}

/** 庆祝反馈 — 带音效 */
export function feedbackCelebrate() {
  playCelebrate();
}
