"use client";

import { useState, useRef, useCallback, useEffect } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getRandomComplete } from "@/lib/learningMessages";
import { playFlip, playDrop, playClick, playCelebrate } from "@/lib/sounds";

type DemoTab = "symmetry" | "translation" | "rotation";

const TABS: { key: DemoTab; icon: string; label: string; color: string }[] = [
  { key: "symmetry", icon: "📄", label: "翻折纸张", color: "var(--primary)" },
  { key: "translation", icon: "🚗", label: "推动小车", color: "var(--accent2)" },
  { key: "rotation", icon: "🎡", label: "转动风车", color: "var(--accent)" },
];

export default function TouchPage() {
  const [tab, setTab] = useState<DemoTab>("symmetry");
  const [doneSymmetry, setDoneSymmetry] = useState(false);
  const [doneTranslation, setDoneTranslation] = useState(false);
  const [doneRotation, setDoneRotation] = useState(false);
  const [showFinish, setShowFinish] = useState(false);
  const [completeMsg, setCompleteMsg] = useState("");
  useEffect(() => { setCompleteMsg(getRandomComplete()); }, []);

  const allDone = doneSymmetry && doneTranslation && doneRotation;

  useEffect(() => {
    if (allDone && !showFinish) {
      const t = setTimeout(() => {
        setShowFinish(true);
        playCelebrate();
      }, 600);
      return () => clearTimeout(t);
    }
  }, [allDone, showFinish]);

  const currentTab = TABS.find((t) => t.key === tab)!;

  return (
    <StepShell topicId="motion" stepId="touch">
      <div className="space-y-5">
        {/* 三个演示切换 */}
        <div className="flex justify-center gap-2">
          {TABS.map((t) => {
            const done =
              (t.key === "symmetry" && doneSymmetry) ||
              (t.key === "translation" && doneTranslation) ||
              (t.key === "rotation" && doneRotation);
            return (
              <button
                key={t.key}
                onClick={() => setTab(t.key)}
                className={`relative flex items-center gap-1.5 rounded-full px-3 py-2 text-sm font-medium transition-all ${
                  tab === t.key
                    ? "bg-[var(--bg-card)] text-[var(--text)] shadow-[var(--shadow-sm)]"
                    : "text-[var(--text-secondary)] hover:bg-[var(--bg-card)]/60"
                }`}
              >
                <span>{t.icon}</span>
                <span className="hidden sm:inline">{t.label}</span>
                {done && (
                  <span className="absolute -top-1 -right-1 flex h-5 w-5 items-center justify-center rounded-full bg-[var(--signal-success)] text-xs text-white">
                    ✓
                  </span>
                )}
              </button>
            );
          })}
        </div>

        {/* 轴对称：翻折纸张 */}
        {tab === "symmetry" && (
          <SymmetryDemo onComplete={() => setDoneSymmetry(true)} />
        )}

        {/* 平移：推动小车 */}
        {tab === "translation" && (
          <TranslationDemo onComplete={() => setDoneTranslation(true)} />
        )}

        {/* 旋转：转动风车 */}
        {tab === "rotation" && (
          <RotationDemo onComplete={() => setDoneRotation(true)} />
        )}

        {/* 进度提示 */}
        <div className="rounded-[var(--radius-sm)] bg-[var(--bg-card)]/60 p-3 text-center text-sm text-[var(--text-secondary)]">
          已探索{" "}
          <span className="font-bold text-[var(--text)]">
            {[doneSymmetry, doneTranslation, doneRotation].filter(Boolean).length}
          </span>{" "}
          / 3 种运动
        </div>

        {/* 完成卡片 */}
        {showFinish && (
          <div className="animate-float-in rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)]">
            <div className="text-5xl animate-bounce-soft">✋</div>
            <h2 className="mt-3 text-xl font-bold text-[var(--text)]">
              {completeMsg}
            </h2>
            <p className="mt-2 text-[var(--text-secondary)]">
              你用手感受了三种运动：<br />
              <span className="font-bold text-[var(--primary)]">翻折</span>、
              <span className="font-bold text-[var(--accent2)]">推动</span>、
              <span className="font-bold text-[var(--accent)]">转动</span>
              <br />
              它们都是生活中常见的运动现象！
            </p>
            <div className="mt-6 flex flex-wrap items-center justify-center gap-3">
              <Link
                href="/learn/motion/compare"
                className="rounded-full bg-[var(--accent)] px-6 py-3 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:-translate-y-0.5 hover:shadow-[var(--shadow-md)]"
              >
                下一步：比一比 →
              </Link>
            </div>
          </div>
        )}
      </div>
    </StepShell>
  );
}

// ========== 轴对称演示 ==========
function SymmetryDemo({ onComplete }: { onComplete: () => void }) {
  const [folded, setFolded] = useState(false);
  const [foldCount, setFoldCount] = useState(0);
  const foldRef = useRef(0);

  const handleFold = () => {
    setFolded((f) => !f);
    foldRef.current += 1;
    setFoldCount(foldRef.current);
    playFlip();
    if (foldRef.current >= 3) {
      onComplete();
    }
  };

  return (
    <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
      <div className="text-center">
        <h3 className="text-lg font-bold text-[var(--text)]">📄 翻折一张纸</h3>
        <p className="mt-1 text-sm text-[var(--text-secondary)]">
          点一点纸张，看看对折后两边会怎样
        </p>
      </div>

      {/* 纸张翻折 SVG */}
      <div className="mt-6 flex justify-center">
        <div
          className="relative cursor-pointer select-none"
          onClick={handleFold}
          style={{ perspective: "600px" }}
        >
          <svg viewBox="0 0 300 200" className="h-48 w-72">
            {/* 左边（固定） */}
            <rect
              x="50"
              y="30"
              width="100"
              height="140"
              fill="#FEF3C7"
              stroke="#F59E0B"
              strokeWidth="2"
              rx="4"
            />
            {/* 左边上的图案 */}
            <circle cx="100" cy="70" r="12" fill="#FB7185" opacity="0.7" />
            <rect x="85" y="100" width="30" height="20" fill="#38BDF8" opacity="0.7" rx="3" />
            <polygon points="100,140 88,155 112,155" fill="#34D399" opacity="0.7" />

            {/* 右边（可翻折） */}
            <g
              style={{
                transformOrigin: "150px 100px",
                transform: folded ? "rotateY(-160deg)" : "rotateY(0deg)",
                transition: "transform 0.8s cubic-bezier(0.4, 0, 0.2, 1)",
                backfaceVisibility: "hidden",
              }}
            >
              <rect
                x="150"
                y="30"
                width="100"
                height="140"
                fill="#FEF3C7"
                stroke="#F59E0B"
                strokeWidth="2"
                rx="4"
              />
              {/* 右边上的图案（对称的） */}
              <circle cx="200" cy="70" r="12" fill="#FB7185" opacity="0.7" />
              <rect x="185" y="100" width="30" height="20" fill="#38BDF8" opacity="0.7" rx="3" />
              <polygon points="200,140 188,155 212,155" fill="#34D399" opacity="0.7" />
            </g>

            {/* 中间折痕 */}
            <line
              x1="150"
              y1="30"
              x2="150"
              y2="170"
              stroke="#F59E0B"
              strokeWidth="2"
              strokeDasharray="4 4"
              opacity={folded ? 0 : 0.5}
            />

            {/* 折叠后显示"重合"文字 */}
            {folded && (
              <text
                x="100"
                y="105"
                textAnchor="middle"
                fill="#E11D48"
                fontSize="14"
                fontWeight="bold"
                className="animate-float-in"
              >
                两边重合啦！
              </text>
            )}
          </svg>
        </div>
      </div>

      <div className="mt-4 text-center">
        <p className="text-sm text-[var(--text-secondary)]">
          {folded
            ? "对折后两边完全重合——这就是轴对称！"
            : "点击纸张试试看 👆"}
        </p>
        <p className="mt-2 text-xs text-[var(--text-muted)]">
          已翻折 {foldCount} 次（翻折 3 次解锁下一步）
        </p>
      </div>
    </section>
  );
}

// ========== 平移演示 ==========
function TranslationDemo({ onComplete }: { onComplete: () => void }) {
  const [posX, setPosX] = useState(20);
  const [moves, setMoves] = useState(0);
  const moveRef = useRef(0);
  const dragRef = useRef<{ startX: number; startPos: number } | null>(null);
  const trackRef = useRef<HTMLDivElement | null>(null);

  const handleStart = useCallback(
    (clientX: number) => {
      dragRef.current = { startX: clientX, startPos: posX };
    },
    [posX]
  );

  const handleMove = useCallback(
    (clientX: number) => {
      if (!dragRef.current || !trackRef.current) return;
      const track = trackRef.current.getBoundingClientRect();
      const dx = clientX - dragRef.current.startX;
      const dxPercent = (dx / track.width) * 100;
      const newPos = Math.max(0, Math.min(80, dragRef.current.startPos + dxPercent));
      setPosX(newPos);
    },
    []
  );

  const handleEnd = useCallback(() => {
    if (dragRef.current) {
      moveRef.current += 1;
      setMoves(moveRef.current);
      playDrop();
      if (moveRef.current >= 3) {
        onComplete();
      }
    }
    dragRef.current = null;
  }, [onComplete]);

  useEffect(() => {
    const onMove = (e: PointerEvent) => handleMove(e.clientX);
    const onUp = () => handleEnd();
    window.addEventListener("pointermove", onMove);
    window.addEventListener("pointerup", onUp);
    window.addEventListener("pointercancel", onUp);
    return () => {
      window.removeEventListener("pointermove", onMove);
      window.removeEventListener("pointerup", onUp);
      window.removeEventListener("pointercancel", onUp);
    };
  }, [handleMove, handleEnd]);

  return (
    <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
      <div className="text-center">
        <h3 className="text-lg font-bold text-[var(--text)]">🚗 推动小车</h3>
        <p className="mt-1 text-sm text-[var(--text-secondary)]">
          按住小车左右拖动，看看小车是怎么移动的
        </p>
      </div>

      {/* 平移轨道 */}
      <div
        ref={trackRef}
        className="relative mt-6 mx-auto h-28 w-full max-w-[360px] rounded-[var(--radius-sm)] bg-[var(--bg-soft)] overflow-hidden"
      >
        {/* 道路虚线 */}
        <div className="absolute left-0 right-0 top-1/2 -translate-y-1/2 flex gap-3 px-4">
          {Array.from({ length: 10 }).map((_, i) => (
            <div
              key={i}
              className="h-1 w-6 rounded-full bg-[var(--border-light)]"
            />
          ))}
        </div>

        {/* 小车（可拖动） */}
        <div
          className="absolute top-1/2 -translate-y-1/2 cursor-grab active:cursor-grabbing touch-none"
          style={{ left: `${posX}%`, transition: dragRef.current ? "none" : "left 0.1s" }}
          onPointerDown={(e) => {
            e.preventDefault();
            handleStart(e.clientX);
          }}
        >
          <svg viewBox="0 0 80 50" className="w-20 h-12 drop-shadow-md">
            {/* 车身 */}
            <rect x="5" y="20" width="70" height="20" rx="4" fill="#34D399" />
            {/* 车顶 */}
            <path d="M 20 20 L 28 8 L 52 8 L 60 20 Z" fill="#10B981" />
            {/* 窗户 */}
            <rect x="30" y="11" width="10" height="8" fill="#BFDBFE" rx="1" />
            <rect x="44" y="11" width="10" height="8" fill="#BFDBFE" rx="1" />
            {/* 车轮 */}
            <circle cx="22" cy="40" r="7" fill="#1E293B" />
            <circle cx="22" cy="40" r="3" fill="#64748B" />
            <circle cx="58" cy="40" r="7" fill="#1E293B" />
            <circle cx="58" cy="40" r="3" fill="#64748B" />
          </svg>
        </div>

        {/* 起点和终点标记 */}
        <div className="absolute bottom-2 left-2 text-xs text-[var(--text-muted)]">
          起点
        </div>
        <div className="absolute bottom-2 right-2 text-xs text-[var(--text-muted)]">
          终点
        </div>
      </div>

      <div className="mt-4 text-center">
        <p className="text-sm text-[var(--text-secondary)]">
          小车沿着直线移动，形状和大小都没变——这就是平移！
        </p>
        <p className="mt-2 text-xs text-[var(--text-muted)]">
          已推动 {moves} 次（推动 3 次解锁下一步）
        </p>
      </div>
    </section>
  );
}

// ========== 旋转演示 ==========
function RotationDemo({ onComplete }: { onComplete: () => void }) {
  const [rotation, setRotation] = useState(0);
  const [isSpinning, setIsSpinning] = useState(false);
  const [spins, setSpins] = useState(0);
  const spinRef = useRef(0);
  const lastRotationRef = useRef(0);
  const completedRef = useRef(false);
  const animRef = useRef<number | null>(null);

  const spin = () => {
    if (isSpinning) return;
    setIsSpinning(true);
    playClick();

    const targetRotation = rotation + 360 * (2 + Math.random() * 2); // 转2-4圈
    const startRotation = rotation;
    const duration = 2000 + Math.random() * 1000;
    const startTime = performance.now();

    const animate = (now: number) => {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / duration, 1);
      // 缓动效果
      const easeOut = 1 - Math.pow(1 - progress, 3);
      const current = startRotation + (targetRotation - startRotation) * easeOut;
      setRotation(current);

      // 计算转了几圈
      const fullRotations = Math.floor((current - lastRotationRef.current) / 360);
      if (fullRotations > 0) {
        spinRef.current += fullRotations;
        setSpins(spinRef.current);
        lastRotationRef.current += fullRotations * 360;
      }

      if (progress < 1) {
        animRef.current = requestAnimationFrame(animate);
      } else {
        setIsSpinning(false);
        // 更新基准
        const finalFull = Math.floor(targetRotation / 360);
        lastRotationRef.current = finalFull * 360;
        setRotation(finalFull * 360 + (targetRotation - finalFull * 360));

        if (spinRef.current >= 5 && !completedRef.current) {
          completedRef.current = true;
          onComplete();
        }
      }
    };

    animRef.current = requestAnimationFrame(animate);
  };

  return (
    <section className="animate-float-in rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
      <div className="text-center">
        <h3 className="text-lg font-bold text-[var(--text)]">🎡 转动风车</h3>
        <p className="mt-1 text-sm text-[var(--text-secondary)]">
          点一点风车，看看它是怎么转动的
        </p>
      </div>

      {/* 风车 */}
      <div className="mt-6 flex justify-center">
        <div className="relative">
          {/* 风车杆 */}
          <div className="absolute left-1/2 -translate-x-1/2 top-24 w-2 h-28 bg-[#92400E] rounded-full" />

          {/* 风叶 */}
          <div
            className="relative cursor-pointer select-none"
            onClick={spin}
            style={{
              transform: `rotate(${rotation}deg)`,
              transition: isSpinning ? "none" : "transform 0.3s",
            }}
          >
            <svg viewBox="0 0 160 160" className="w-40 h-40">
              {/* 四片风叶 */}
              <g transform="translate(80 80)">
                {/* 叶片 1 - 粉色 */}
                <path
                  d="M 0 0 L 0 -60 Q 25 -55 35 -35 Q 30 -15 0 -5 Z"
                  fill="#FB7185"
                  opacity="0.85"
                />
                {/* 叶片 2 - 蓝色 */}
                <path
                  d="M 0 0 L 60 0 Q 55 25 35 35 Q 15 30 5 0 Z"
                  fill="#38BDF8"
                  opacity="0.85"
                />
                {/* 叶片 3 - 黄色 */}
                <path
                  d="M 0 0 L 0 60 Q -25 55 -35 35 Q -30 15 0 5 Z"
                  fill="#FBBF24"
                  opacity="0.85"
                />
                {/* 叶片 4 - 绿色 */}
                <path
                  d="M 0 0 L -60 0 Q -55 -25 -35 -35 Q -15 -30 -5 0 Z"
                  fill="#34D399"
                  opacity="0.85"
                />
                {/* 中心圆点 */}
                <circle cx="0" cy="0" r="10" fill="#F59E0B" stroke="#D97706" strokeWidth="2" />
                <circle cx="0" cy="0" r="4" fill="#FEF3C7" />
              </g>
            </svg>
          </div>
        </div>
      </div>

      <div className="mt-4 text-center">
        <p className="text-sm text-[var(--text-secondary)]">
          风车绕着中心点转动——这就是旋转！
        </p>
        <p className="mt-2 text-xs text-[var(--text-muted)]">
          已转 {spins} 圈（转满 5 圈解锁下一步）
        </p>
        <button
          onClick={spin}
          disabled={isSpinning}
          className="mt-3 rounded-full bg-[var(--accent)] px-5 py-2 text-sm font-bold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105 disabled:opacity-50"
        >
          {isSpinning ? "转动中..." : "再转一次 🌀"}
        </button>
      </div>
    </section>
  );
}
